import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  AppBar,
  Toolbar,
  Typography,
  IconButton,
  Menu,
  MenuItem,
  Avatar,
} from "@mui/material";
import { useAuth } from "../contexts/AuthContext";

export default function Navbar() {
  const navigate = useNavigate();
  const { auth, logout } = useAuth();
  const { token, roles } = auth || {};
  const [anchorEl, setAnchorEl] = useState(null);

  // ✅ role is always the first role from array
  const role = roles && roles.length > 0 ? roles[0] : null;

  const handleMenuOpen = (event) => setAnchorEl(event.currentTarget);
  const handleMenuClose = () => setAnchorEl(null);

  const handleLogout = () => {
    logout();
    handleMenuClose();
    navigate("/login"); // always return to login after logout
  };

  return (
    <AppBar position="static" sx={{ backgroundColor: "black", px: 2 }}>
      <Toolbar sx={{ display: "flex", justifyContent: "space-between" }}>
        {/* App Title → role-based dashboard */}
        <Typography
          variant="h6"
          sx={{ fontWeight: "bold", cursor: "pointer" }}
          onClick={() => {
            if (role === "rider") navigate("/rider-dashboard");
            else if (role === "user") navigate("/user-dashboard");
            else if (role === "admin") navigate("/admin-dashboard");
            else navigate("/");
          }}
        >
          Rider App
        </Typography>

        {/* Right Side Avatar & Menu */}
        {token && (
          <>
            <IconButton onClick={handleMenuOpen} sx={{ p: 0 }}>
              <Avatar sx={{ bgcolor: "orangered" }}>
                {role === "rider" ? "R" : role === "user" ? "U" : "A"}
              </Avatar>
            </IconButton>

            <Menu
              anchorEl={anchorEl}
              open={Boolean(anchorEl)}
              onClose={handleMenuClose}
              PaperProps={{ elevation: 3, sx: { mt: 1.5, borderRadius: 2 } }}
            >
              {/* ADMIN MENU */}
              {role === "admin" && (
                <>
                  <MenuItem
                    onClick={() => {
                      navigate("/admin-dashboard");
                      handleMenuClose();
                    }}
                  >
                    Dashboard
                  </MenuItem>
                  <MenuItem onClick={handleLogout} sx={{ color: "red" }}>
                    Logout
                  </MenuItem>
                </>
              )}

              {/* USER MENU */}
              {role === "user" && (
                <>
                  <MenuItem
                    onClick={() => {
                      navigate("/booking");
                      handleMenuClose();
                    }}
                  >
                    Booking
                  </MenuItem>
                  <MenuItem
                    onClick={() => {
                      navigate("/history");
                      handleMenuClose();
                    }}
                  >
                    History
                  </MenuItem>
                  <MenuItem
                    onClick={() => {
                      navigate("/profile");
                      handleMenuClose();
                    }}
                  >
                    Profile
                  </MenuItem>
                  <MenuItem
                    onClick={() => {
                      navigate("/parcel");
                      handleMenuClose();
                    }}
                  >
                    Parcel
                  </MenuItem>
                  <MenuItem onClick={handleLogout} sx={{ color: "red" }}>
                    Logout
                  </MenuItem>
                </>
              )}

              {/* RIDER MENU */}
              {role === "rider" && (
                <>
                  <MenuItem
                    onClick={() => {
                      navigate("/history");
                      handleMenuClose();
                    }}
                  >
                    History
                  </MenuItem>
                  <MenuItem
                    onClick={() => {
                      navigate("/profile");
                      handleMenuClose();
                    }}
                  >
                    Profile
                  </MenuItem>
                  <MenuItem onClick={handleLogout} sx={{ color: "red" }}>
                    Logout
                  </MenuItem>
                </>
              )}
            </Menu>
          </>
        )}
      </Toolbar>
    </AppBar>
  );
}
